var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"…그리하여, 오늘 하루 동안 인공지능 주르를 대신해 내 일일 조수가 되어주기로 한 케이시 양이야.","JPN":"……というわけで、今日一日、J.O.U.Rの代わりに私の助手になってもらうケイシーね。","ENG":"...And so, this is Kaci, who will be my daily assistant for the day on behalf of the AI J.O.U.R.","TWN":"……於是今天一整天，卡西小姐將代替人工智慧J.O.U.R，成為我的臨時助手。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"잘…! 부탁드립니다!","JPN":"よろしく……！　お願いします！","ENG":"Pleased...! To meet you all!","TWN":"請……！請多指教！"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으응, 우리야말로 잘 부탁해.","JPN":"うん、こっちこそよろしくね。","ENG":"We're pleased to meet you too!","TWN":"嗯，我們這邊才要請你多幫忙。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데… 그 사고는 수업시간에 숨어서 땡땡이를 치던 이디스 선배 잘못이 크지 않아? 업보라고 생각하는데.","JPN":"でもさ……あの事故は、授業中に隠れてサボってたイーディス先輩が悪いんじゃない？　自業自得だと思うんだけど。","ENG":"But... Wasn't that accident more Edith's fault because she was skipping class? I think it's karma coming to bite you back.","TWN":"不過……那場意外不應該是翹課躲起來的伊蒂絲學姐的錯嗎？我覺得算是現世報。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"땡땡이라니, 표현이 잘못됐어.","JPN":"サボるという表現は間違ってる。","ENG":"Skipping class? That's incorrect.","TWN":"什麼翹課，你這個說法不太正確。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"내 꿈은 인류가 수평비행을 하는 의자 위에서 편안한 숙면을 가질 수 있게 되는 거야. 난 그런 인류의 미래를 위해 몸소 시험을 하고 있었을 뿐이라구우.","JPN":"私の夢は、人類が水平飛行をする椅子の上で安眠できるようになること。私はそんな人類の未来のために、体を張って実験をしてただけだよ。","ENG":"My dream is that mankind will be able to sleep comfortably on a chair that flies horizontally. And I was personally conducting a test for the future of mankind.","TWN":"我的夢想，是讓人類能在水平飛行的椅子上安穩入睡。我只是親自在為人類的未來進行測試而已啦。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런 꿈 얘기 처음 듣거든? 케이시를 데려온 것도 결국 선배가 일하기 귀찮아서 그런 거 아냐?","JPN":"そんな夢の話初耳なんですけど～？　ケイシーちゃんを連れてきたのも、結局先輩が働きたくないからじゃないの？","ENG":"That's the first time I ever heard about such a dream. But didn't you bring Kaci along because you're too lazy and don't want to work?","TWN":"我還是第一次聽說這種夢想耶？你帶卡西來，該不會只是因為學姐不想工作吧？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아, 아니에요! 이디스 선배는 괜찮다고 했지만, 제가 억지로 돕고 싶다고 한걸요!","JPN":"ち、違います！　イーディス先輩は必要ないって言ったのに、あたしが無理を言って手伝わせてもらってるんです！","ENG":"N-no! Edith said I didn't have to, but I insisted I wanted to help!","TWN":"不、不是的！雖然伊蒂絲學姐說沒關係，是我自己硬要來幫忙的！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…그으래?","JPN":"……そ～お？","ENG":"...Is that so?","TWN":"……是嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아무튼, 오늘 두 사람이 맡아줘야 할 일을 알려 줄게.","JPN":"とにかく、今日二人にお願いしたいことを教えるね。","ENG":"Anyway, I'll tell you two what tasks you'll be doing today.","TWN":"總之，我來說明一下今天你們兩個要負責的工作。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그쪽은 어때~?","JPN":"そっちはどう～？","ENG":"How does it look on your side?","TWN":"那邊怎麼樣～？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"문제없어요. 송수관이 막힌 건 아닌 것 같아요.","JPN":"問題ありません。送水管が詰まっているわけではないみたいです。","ENG":"No problems. I don't think the water pipe is clogged.","TWN":"沒問題，看起來不是水管堵塞。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그럼, 수영장 물이 안 나오는 원인은 급수시스템의 고장일 가능성이 높아.","JPN":"じゃあ、プールの水が出ない原因は、給水システムに問題が生じた可能性が高いね。","ENG":"Then, there is a high possibility that the cause of the pool water not coming out is a malfunction in the water supply system.","TWN":"那麼泳池沒水的原因，很可能是供水系統故障。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"인공지능이 고장 나서 원격으로 점검할 수 없는 상태이니, 직접 설비 안으로 들어가서 확인해야 할 거야.","JPN":"人工知能が壊れたせいで、リモート点検ができない状態だから、直接設備に入って確かめてみないと。","ENG":"Since the AI's down and we can't do a remote inspection, we'll have to go into the facility and check it out ourselves.","TWN":"因為人工智慧壞了，現在沒辦法遠端檢查，只能直接進入設備確認了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네! 제가 안으로 들어가볼게요!","JPN":"はい！　あたしが中に入ってみます！","ENG":"Okay! I'll take a look inside!","TWN":"是！我進去看看！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"조명이 없어서 어두울 텐데~ 혼자 무섭지 않겠어?","JPN":"光がないから暗いと思うけど～1人で怖くない？","ENG":"It's going to be pitch-dark without any lights. Won't you be scared of being all alone in there?","TWN":"裡面沒有照明，會很暗喔～你一個人不會怕嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"괜찮아요. 익숙해서 오히려 편하거든요, 그런 거.","JPN":"大丈夫です。慣れてるので、むしろ気持ちが落ち着くんです。","ENG":"I'm all right. I'm used to places like this, so it's actually quite comfortable.","TWN":"沒關係，我習慣了，反而覺得很自在。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐음, 그렇구나- 케이시는 어둠 속에서 끔찍한 괴물이 튀어나와도 놀라지 않는 타입이구나.","JPN":"ふーん、そっか。ケイシーは闇の中から恐ろしい化け物が出てきても驚かないタイプなんだね。","ENG":"Hmm, I see. So Kaci's not the type to get startled when a scary monster jumps out from the dark.","TWN":"哦～原來如此。卡西是那種就算在黑暗中有可怕怪物跳出來，也不會嚇到的類型啊。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그렇게 말씀하시니까 갑자기 무서워졌어요.","JPN":"そう言われたら……急に怖くなりました。","ENG":"Well, now that you say it like that, I'm scared.","TWN":"你這麼說，我突然開始害怕了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"안으로 들어왔어요. 어떻게 할까요?","JPN":"中に入りました。これからどうしましょうか？","ENG":"I'm in. What should I do next?","TWN":"我進來了，接下來要怎麼做？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"파이프를 따라 움직이면 수동조작이 가능한 계기판이 보일 거야.","JPN":"パイプをたどって行けば、手動操作できる計器盤が見えるはずだよ。","ENG":"Move along the pipe and you'll see a panel that can be manually operated.","TWN":"沿著管線走，你會看到可以手動操作的控制面板。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"여기… 생각보다 어둡고 넓네요.","JPN":"ここ……思ったより暗くて、広いんですね。","ENG":"It's... darker and more spacious in here than I thought.","TWN":"這裡……比想像中還暗又大呢。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"어둠 속에서 부기맨이 손을 뻗어올지도 모른다구?","JPN":"闇の中からブギーマンが手を伸ばしてくるかもしれないよ？","ENG":"A boogeyman might reach his hand out to you from the dark.","TWN":"說不定會有躲在黑暗中的怪物伸出手喔？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그, 그렇게까지 말씀하실 필요 있는 건가요…?","JPN":"そ、そんなこと言う必要ありますか……？","ENG":"D-did you have to say that to me...?","TWN":"有、有必要說得這麼恐怖嗎……？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"미안. 분위기전환용으로 말해봤어.","JPN":"ごめん。雰囲気を変えるつもりで言ってみただけ。","ENG":"Sorry. I was trying to change the mood a bit.","TWN":"抱歉，我只是想轉換一下氣氛。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그치만 조심해~ 얼마전에 그쯤에서 생체반응이 감지된 적이 있거든.","JPN":"でも気をつけてね～この前、その辺りで生体反応が感知されたことがあるからね。","ENG":"But be careful! There was a bio signal detected around there recently.","TWN":"不過要小心喔～前陣子這附近曾偵測到生命反應。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"네…?","JPN":"えっ……？","ENG":"Huh...?","TWN":"咦……？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"으으… 정말로 부기맨이 나타나면 어떡하죠?","JPN":"うう……本当にブギーマンが現れたらどうしましょう？","ENG":"Ngh... What do I do if a boogeyman really does come out?","TWN":"嗚……如果真的出現怪物怎麼辦？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"뭐어- 부기맨은 일반인을 상대로 하는 괴담이니까- 카운터인 케이시의 펀치 한 방이면 해치우지 않을까 싶은데.","JPN":"まあ～ブギーマンは大衆向けの怪談だし～ケイシーはカウンターだからパンチ一発で倒せるんじゃないかな。","ENG":"Well, because the boogeyman is an urban legend to scare non-Counters. And since you're a Counter, you can defeat it with just one punch, Kaci.","TWN":"唉唷～怪物本來就是嚇唬普通人的怪談啦～身為制裁者的卡西，一拳就能解決吧？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"해… 해치울게요! 뭔가 나타나면 펀치로…!","JPN":"た……倒します！　何かが現れたらパンチで……！","ENG":"I-I'll try! If anything pops up, I'll punch it, and–!","TWN":"我、我會解決的！如果出現的話，就用拳頭……！"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};